def get_conn(self):
    """
    Lazily initialize and return the Azure Cosmos DB client.

    Returns:
        cosmos_client.CosmosClient: The Cosmos client instance.
    """
    # Return existing client if already initialized
    if getattr(self, "cosmos_client", None) is not None:
        return self.cosmos_client

    # Validate required attributes
    if not getattr(self, "endpoint_uri", None):
        raise ValueError("endpoint_uri must be set to initialize CosmosClient.")
    if not getattr(self, "master_key", None):
        raise ValueError("master_key must be set to initialize CosmosClient.")

    # Initialize the Python Azure Cosmos DB client
    self.cosmos_client = cosmos_client.CosmosClient(
        self.endpoint_uri, {'masterKey': self.master_key}
    )

    return self.cosmos_client
